import { MerkleTree, verifyMerkleProof } from '../merkle-tree';
function makeLeaves(n: number): string[] {
  return Array.from({ length: n }, (_, i) => String.fromCharCode(96)+"leaf-"+i+String.fromCharCode(96));
}
